    public function __construct()
    {
        $this->run();
    }

    private function run()
    {
        $chunkedOrders = array_chunk(self::UIDS , 20);
        foreach ($chunkedOrders as $ordersData) {
            foreach ($ordersData as $order) {
                $this->pdnCalculation->run(null, $order->order_number, $order->contract_number);
            }
        }
    }


